-- reverse: create "chat_turn_summaries_mv" view
DROP VIEW `chat_turn_summaries_mv`;
-- reverse: drop "chat_turn_summaries_mv" view
CREATE MATERIALIZED VIEW `chat_turn_summaries_mv` TO `chat_turn_summaries` AS WITH toUnixTimestamp64Nano(toDateTime64('2026-06-23 18:15:00', 9, 'UTC')) AS chat_turn_cutoff_unix_nano SELECT gram_project_id, chat_id, toString(attributes.prompt.id) AS turn_id, toString(attributes.query_source) AS query_source, toString(attributes.skill.name) AS skill_name, toString(attributes.agent.name) AS agent_name, toString(attributes.mcp_server.name) AS mcp_server_name, toString(attributes.mcp_tool.name) AS mcp_tool_name, multiIf(toString(attributes.model) != '', toString(attributes.model), toString(attributes.gen_ai.request.model) != '', toString(attributes.gen_ai.request.model), toString(attributes.gen_ai.response.model)) AS model, toString(attributes.user.attributes.department_name) AS department_name, toString(attributes.user.attributes.job_title) AS job_title, toString(attributes.user.attributes.employee_type) AS employee_type, toString(attributes.user.attributes.division_name) AS division_name, toString(attributes.user.attributes.cost_center_name) AS cost_center_name, user_email AS user_email, hook_source, arraySort(JSONExtract(ifNull(toJSONString(attributes.user.roles), '[]'), 'Array(String)')) AS roles, arraySort(JSONExtract(ifNull(toJSONString(attributes.user.groups), '[]'), 'Array(String)')) AS groups, min(time_unix_nano) AS start_time_unix_nano, max(time_unix_nano) AS end_time_unix_nano, sum(toInt64OrZero(toString(attributes.input_tokens))) AS input_tokens, sum(toInt64OrZero(toString(attributes.output_tokens))) AS output_tokens, ((sum(toInt64OrZero(toString(attributes.input_tokens))) + sum(toInt64OrZero(toString(attributes.output_tokens)))) + sum(toInt64OrZero(toString(attributes.cache_read_tokens)))) + sum(toInt64OrZero(toString(attributes.cache_creation_tokens))) AS total_tokens, sum(toInt64OrZero(toString(attributes.cache_read_tokens))) AS cache_read_tokens, sum(toInt64OrZero(toString(attributes.cache_creation_tokens))) AS cache_creation_tokens, sum(toFloat64OrZero(toString(attributes.cost_usd))) AS cost_usd, sum(toInt64OrZero(toString(attributes.cost_usd_micros))) AS cost_usd_micros FROM telemetry_logs WHERE (time_unix_nano >= chat_turn_cutoff_unix_nano) AND (chat_id != '') AND (toString(attributes.prompt.id) != '') AND ((toString(attributes.event.name) = 'api_request') OR (body = 'claude_code.api_request')) AND ((service_name = 'claude-code') OR (toString(resource_attributes.service.name) = 'claude-code') OR startsWith(body, 'claude_code.')) GROUP BY gram_project_id, chat_id, turn_id, query_source, skill_name, agent_name, mcp_server_name, mcp_tool_name, model, department_name, job_title, employee_type, division_name, cost_center_name, user_email, hook_source, roles, groups;
